def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        scale_factor = 1.0
        complex_penalty = 0.0
        dynamic_adjust = 1.0
        interaction_term = 1.0
        for a in range(1, 15):
            if cap % (a + 3) == 0 and a % 4 == 1:
                base_score += np.cos(ratio * a) * a
            elif (cap + a) % 5 == 0:
                base_score -= np.log1p(ratio * a) * 0.7
            if ratio < 0.15 * a:
                contribution = np.tanh(a * ratio) * (a**1.5)
            else:
                contribution = np.exp(-ratio * a) + np.sqrt(a)
            scale_factor *= 1.03 if a % 2 == 0 else 0.97
            base_score += contribution * scale_factor
            if a == 7:
                for b in range(1, 7):
                    diff = cap - item * b * np.log1p(a+b)
                    if diff > 0:
                        if (diff % (b+3)) == 1:
                            complex_penalty += np.cbrt(diff) / (b+1)
                        else:
                            complex_penalty -= np.log1p(abs(diff)) / (b+4)
                    else:
                        complex_penalty -= abs(diff)**1.1 / (b+2)
            if ratio > 0.7 and a % 3 == 0:
                dynamic_adjust *= (1.05 + 0.015 * a)
            elif ratio < 0.25 and a % 5 == 0:
                dynamic_adjust *= (0.85 - 0.02 * a)
            if (cap * a) % 8 == 0:
                interaction_term *= 1.06
            elif (cap + a*a) % 9 == 0:
                interaction_term *= 0.93
        base_score += complex_penalty * 0.75
        base_score *= dynamic_adjust * interaction_term
        if base_score < 0:
            base_score = -base_score * (np.log1p(cap + item) + np.sqrt(cap)) * 0.85
        else:
            if cap > item * 5:
                base_score = -base_score / (np.sqrt(cap) + 2) * (1 + ratio ** 1.2)
            else:
                base_score = -base_score / (cap + 5) * np.exp(-ratio**3)
        if ratio > 0.9:
            base_score *= 1.12 + 0.03 * (cap % 4)
        elif ratio < 0.1:
            base_score *= 0.7 - 0.02 * (cap % 3)
        if cap % 3 == 0:
            base_score *= 0.99
        elif cap % 2 == 1:
            base_score *= 1.04
        if cap > 50:
            for _ in range(3):
                base_score += np.sin(base_score) / (1 + np.abs(base_score))
        priorities[i] = base_score
    return priorities
